const raw = $input.first().json;
const query = $('Webhook - GET /vmm-fetch-attachments').first().json.query || {};
const messageId = query.messageId || '';
const safeStamp = new Date().toISOString().replace(/[:.]/g, '-');

const attachments = (raw.value || [])
  .filter(a => !a.isInline && a.name && a.contentBytes)
  .map((a, idx) => {
    const safeName = (a.name || `attachment-${idx + 1}`).replace(/[\\/:*?"<>|]/g, '_');
    const fileName = `${safeStamp}_${safeName}`;

    return {
      json: {
        sourceMessageId: messageId,
        originalName: a.name || safeName,
        name: fileName,
        size: a.size || 0,
        contentType: a.contentType || 'application/octet-stream'
      },
      binary: {
        data: {
          data: a.contentBytes,
          mimeType: a.contentType || 'application/octet-stream',
          fileName
        }
      }
    };
  });

if (!attachments.length) {
  return [{ json: { noAttachments: true, attachments: [] } }];
}

return attachments;

const uploaded = $input.all();

const attachments = uploaded
  .filter(i => !i.json.noAttachments)
  .map(i => {
    const id = i.json.id || i.json.fileId || '';
    return {
      id,
      name: i.json.originalName || i.json.name || i.json.fileName || 'attachment',
      driveName: i.json.name || i.json.fileName || '',
      size: i.json.size || 0,
      contentType: i.json.contentType || '',
      viewLink: id ? `https://drive.google.com/file/d/${id}/view` : (i.json.webViewLink || ''),
      downloadLink: id ? `https://drive.google.com/uc?export=download&id=${id}` : (i.json.webContentLink || '')
    };
  });

return [{ json: { success: true, count: attachments.length, attachments } }];
